var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"누가 고물 함선 아니랄까 봐 겁나게 흔들리네. 다이브하다 부서지는 거 아냐?","JPN":"オンボロ艦船らしく、 とんでもない揺れだな。ダイブ中に壊れるんじゃないか？","ENG":"That's some serious turbulence. I should've known with this crappy old ride. What if it falls apart during the Dive?","TWN":"這還真是老古董艦船，晃得也太厲害了。不會躍入到一半就碎了吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"재수없는 소리 하지 마. 진짜 그럴 것 같잖아.","JPN":"縁起でもないこと言うな。マジでそうなりそうだから。","ENG":"Don't jinx us like that. It could actually happen.","TWN":"別烏鴉嘴，萬一真的應驗了怎麼辦。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우...... 우으......","JPN":"う……うぅ……","ENG":"Ugh... Blegh...","TWN":"嗚……嗚哇……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이게 다이브 멀미구나...... 눈이 핑핑 돌아......","JPN":"これがダイブ酔い……目が回る……","ENG":"So this is what Dive sickness feels like... The entire world is spinning...","TWN":"這就是躍入出現的眩暈啊……兩眼都冒金星了……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니가 걱정하던 게 이래서였을까......?","JPN":"リタお姉ちゃんが心配していたのはこれ……？","ENG":"Is this why Rita was worried?","TWN":"麗塔姐姐擔心的是這個嗎……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"따라오겠다고?","JPN":"ついてくるって？","ENG":"You want to tag along?","TWN":"你要一起去？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹! 언니가 가는데 저도 당연히 가야죠!","JPN":"はいっ！　リタお姉ちゃんが行くなら当然私もついて行かないと！","ENG":"Yup! If you're going, I should be there too!","TWN":"嗯！姐姐去我當然也要去嘍！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니. 넌 이면세계가 어떤 곳인지 몰라.","JPN":"いや、お前は裏世界がどんな場所なのか知らないだろ。","ENG":"No. You have no idea what the Counterside is like.","TWN":"不，你不知道異界是個怎樣的地方。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"비즈니스 모텔에 방 하나 구해 줄 테니 얌전히 기다리고 있어.","JPN":"ビジネスホテルに部屋をとってやるからそこで大人しく待っていろ。","ENG":"I'll get you a room at a business hotel. Just stay put there.","TWN":"我會在商務旅館給你訂個房間，你乖乖等我回來。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만 윌버 씨한테 기회를 달라고 부탁한 사람은 저잖아요. 모른 척 하긴 싫어요.","JPN":"でもウィルバーさんにチャンスを与えてほしいと頼んだのは私です。責任持って見届けないと。","ENG":"But I'm the one who asked you to give Mr. Wilbur another chance. I can't just send him off without me.","TWN":"但是請求給韋爾伯一次機會的人是我啊。我不想置身事外。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 부모 닮아서 참 고집불통이군......","JPN":"はあ……親に似て頑固だな……","ENG":"Ugh... Stubborn, just like your parents.","TWN":"唉……怎麼跟她父母一樣，都這麼固執……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어차피 여기 두고 가도 사고나 치겠지.","JPN":"どうせ置いていってもまた何かやらかしそうだろう。","ENG":"I suppose you'll just get into more trouble if I leave you here.","TWN":"把你留在這裡應該也會惹禍吧。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"대신 거기선 절대로 설치지 마.","JPN":"連れていく代わりに、そこでは勝手な行動は絶対しないと約束しろ。","ENG":"Fine. But don't do anything you're not told to when we're down there.","TWN":"但你到了那裡，答應我一定不能搗亂。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럼요! 당연하죠!","JPN":"はい！　もちろんです！","ENG":"Right on! Of course!","TWN":"當然啦！當然！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"무섭다...... 이면세계......","JPN":"怖いなぁ……裏世界……","ENG":"I had no idea... the Counterside is this terrifying...","TWN":"異界……好恐怖啊……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"미안해요, 리타 언니...... 저 먼저 가요...... 히잉......","JPN":"ごめんなさい、リタお姉ちゃん……私……先に逝きます……ひぃん……","ENG":"I'm sorry, Rita... but I think this is it for me... Hngh...","TWN":"對不起，麗塔姐姐……我先走了……嚶嚶……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_Q","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_Q","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};